246→      output.success(`${plugin.name}${plugin.source ? ` (${plugin.source})` : ''} — already installed`);
247→      continue;
248→    }
249→
250→    // Attempt install
251→    const result = installPlugin(plugin);
252→
253→    if (result.success) {
254→      results.installed.push(plugin);
255→      output.success(`${plugin.name}${plugin.source ? ` (${plugin.source})` : ''}`);
256→    } else {
257→      results.failed.push({ plugin, error: result.error });
258→      output.warn(`${plugin.name} — install failed (${result.error})`);
259→    }
260→  }
261→
262→  // Summary
263→  output.blank();
264→  const total = results.installed.length + results.skipped.filter(s => s.reason === 'already-installed').length;
265→  const failCount = results.failed.length;
266→  if (failCount === 0) {
267→    output.info(`${total}/${RECOMMENDED_PLUGINS.length} plugins installed (project scope)`);
268→  } else {
269→    output.info(`${total}/${RECOMMENDED_PLUGINS.length} plugins installed, ${failCount} failed`);
270→    for (const f of results.failed) {
271→      const id = f.plugin.source
272→        ? `${f.plugin.name}@${f.plugin.source}`
273→        : f.plugin.name;
274→      output.info(`  Run manually: claude plugin install ${id} --scope project`);
275→    }
276→  }
277→
278→  return results;
279→}
280→
