125→function doStatus(targetDir) {
126→  const installed = manifest.readVersion(targetDir);
127→  if (!installed) {
128→    output.info('Founder OS is not installed in this directory.');
129→    output.info('Run: npx founder-os@latest --init');
130→    return;
131→  }
132→
133→  const manifestData = manifest.readManifest(targetDir);
134→  if (!manifestData) {
135→    output.warn('Installation found but manifest is missing. Run --init to repair.');
136→    return;
137→  }
