139→  let managed = 0, modified = 0, removed = 0;
140→  for (const [relKey, entry] of Object.entries(manifestData.files)) {
141→    const filePath = path.join(targetDir, relKey);
142→    if (!fs.existsSync(filePath)) {
143→      removed++;
144→    } else if (entry.checksum && manifest.computeChecksum(filePath) !== entry.checksum) {
145→      modified++;
