151→  output.info(`Founder OS v${installed.version}`);
152→  output.info(`Installed: ${installed.installedAt}`);
153→  output.info(`Updated: ${installed.updatedAt}`);
154→  output.info(`Files: ${managed} managed, ${modified} modified, ${removed} removed`);
155→
156→  if (installed.version !== VERSION) {
157→    output.blank();
158→    output.info(`Update available: v${VERSION}`);
159→    output.info('Run: npx founder-os@latest --init');
160→  }
161→}
