 1→// lib/manifest.js
 2→// Manifest read/write and SHA-256 checksum computation
 3→'use strict';
 4→
 5→const fs = require('fs');
 6→const path = require('path');
 7→const crypto = require('crypto');
 8→
 9→const MANIFEST_PATH = '.founderOS/manifest.json';
10→const VERSION_PATH = '.founderOS/version.json';
11→
12→function computeChecksum(filePath) {
13→  const content = fs.readFileSync(filePath);
14→  return 'sha256:' + crypto.createHash('sha256').update(content).digest('hex');
15→}
16→
17→function readManifest(baseDir) {
18→  const manifestFile = path.join(baseDir, MANIFEST_PATH);
19→  if (!fs.existsSync(manifestFile)) return null;
20→  return JSON.parse(fs.readFileSync(manifestFile, 'utf8'));
21→}
22→
23→function writeManifest(baseDir, manifest) {
24→  const manifestFile = path.join(baseDir, MANIFEST_PATH);
25→  fs.writeFileSync(manifestFile, JSON.stringify(manifest, null, 2) + '\n');
26→}
27→
28→function readVersion(baseDir) {
29→  const versionFile = path.join(baseDir, VERSION_PATH);
30→  if (!fs.existsSync(versionFile)) return null;
31→  return JSON.parse(fs.readFileSync(versionFile, 'utf8'));
32→}
33→
34→function writeVersion(baseDir, version) {
35→  const versionFile = path.join(baseDir, VERSION_PATH);
36→  const data = {
37→    version,
38→    installedAt: readVersion(baseDir)?.installedAt || new Date().toISOString(),
39→    updatedAt: new Date().toISOString(),
40→  };
41→  fs.writeFileSync(versionFile, JSON.stringify(data, null, 2) + '\n');
42→}
43→
44→function createEmptyManifest(version) {
45→  return {
46→    version,
47→    installedAt: new Date().toISOString(),
48→    updatedAt: new Date().toISOString(),
49→    files: {},
50→  };
51→}
52→
53→function addFileToManifest(manifest, relativePath, checksum, status, extra) {
54→  manifest.files[relativePath] = { checksum, status, ...extra };
55→}
56→
57→module.exports = {
58→  computeChecksum,
59→  readManifest,
60→  writeManifest,
61→  readVersion,
62→  writeVersion,
63→  createEmptyManifest,
64→  addFileToManifest,
65→  MANIFEST_PATH,
66→  VERSION_PATH,
67→};
68→

