206→      timeout: 60000,
207→    });
208→    return { success: true };
209→  } catch (err) {
210→    const msg = err.stderr
211→      ? err.stderr.toString().trim().split('\n')[0]
212→      : 'unknown error';
213→    return { success: false, error: msg };
214→  }
215→}
216→
217→function installRecommended(manifestData, force) {
218→  const existingPlugins = manifestData?.plugins || {};
219→  const results = { installed: [], skipped: [], failed: [] };
220→
221→  // Check claude CLI first
222→  if (!checkClaudeCli()) {
223→    output.blank();
224→    output.warn('Claude CLI not found — skipping plugin installation');
225→    output.info('  Install Claude Code first, then run:');
226→    output.info('  npx founder-os@latest --init --with-plugins');
227→    return results;
228→  }
229→
230→  output.blank();
231→  output.info('Installing recommended plugins...');
232→  output.blank();
233→
234→  for (const plugin of RECOMMENDED_PLUGINS) {
235→    const key = pluginKey(plugin);
236→    const existing = existingPlugins[key];
237→
238→    // Always skip user-removed plugins — respect user's choice even with --force
239→    if (existing?.status === 'user-removed') {
240→      results.skipped.push({ plugin, reason: 'user-removed' });
241→      continue;
242→    }
243→
244→    // Skip already installed (unless --force to retry)
245→    if (existing?.status === 'installed' && !force) {
246→      results.skipped.push({ plugin, reason: 'already-installed' });
247→      output.success(`${plugin.name}${plugin.source ? ` (${plugin.source})` : ''} — already installed`);
248→      continue;
249→    }
250→
251→    // Attempt install
252→    const result = installPlugin(plugin);
253→
254→    if (result.success) {
255→      results.installed.push(plugin);
256→      output.success(`${plugin.name}${plugin.source ? ` (${plugin.source})` : ''}`);
257→    } else {
258→      results.failed.push({ plugin, error: result.error });
259→      output.warn(`${plugin.name} — install failed (${result.error})`);
260→    }
261→  }
262→
263→  // Summary
264→  output.blank();
265→  const total = results.installed.length + results.skipped.filter(s => s.reason === 'already-installed').length;
266→  const failCount = results.failed.length;
267→  if (failCount === 0) {
268→    output.info(`${total}/${RECOMMENDED_PLUGINS.length} plugins installed (project scope)`);
269→  } else {
270→    output.info(`${total}/${RECOMMENDED_PLUGINS.length} plugins installed, ${failCount} skipped`);
271→    for (const f of results.failed) {
272→      const id = f.plugin.source
273→        ? `${f.plugin.name}@${f.plugin.source}`
274→        : f.plugin.name;
275→      output.info(`  Run manually: claude plugin install ${id} --scope project`);
276→    }
277→  }
278→
279→  return results;
280→}
281→
282→module.exports = {
283→  RECOMMENDED_PLUGINS,
284→  checkClaudeCli,
285→  installPlugin,
286→  installRecommended,
287→  pluginKey,
288→};
289→```
